def calc(expr):
    def parse(expr):
        tokens = []
        i = 0
        while i < len(expr):
            if expr[i].isspace():
                i += 1
                continue
            elif expr[i] in "+-*/()":
                tokens.append(expr[i])
                i += 1
            elif expr[i].isdigit():
                num = ""
                while i < len(expr) and expr[i].isdigit():
                    num += expr[i]
                    i += 1
                tokens.append(int(num))
        return tokens

    def evaluate(tokens):
        stack = []
        i = 0
        while i < len(tokens):
            if tokens[i] == "(":
                stack.append(i)
            elif tokens[i] == ")":
                start = stack.pop()
                expr = tokens[start+1:i]
                result = evaluate(expr)
                tokens[start:i+1] = [result]
            elif tokens[i] in "+-*/":
                if len(stack) < 2:
                    raise ValueError("Invalid expression")
                right = stack.pop()
                left = stack.pop()
                if tokens[i] == "+":
                    stack.append(left + right)
                elif tokens[i] == "-":
                    stack.append(left - right)
                elif tokens[i] == "*":
                    stack.append(left * right)
                elif tokens[i] == "/":
                    stack.append(left // right)
            else:
                stack.append(tokens[i])
            i += 1
        return stack[0]

    return evaluate(parse(expr))

