def run_turtle(program):
    directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]  # North, East, South, West
    x, y = 0, 0
    direction_index = 0
    pen_down = False
    marks = set()

    def move(n):
        nonlocal x, y
        for _ in range(n):
            x += directions[direction_index][0]
            y += directions[direction_index][1]
            if pen_down:
                marks.add((x, y))

    def turn_left():
        nonlocal direction_index
        direction_index = (direction_index - 1) % 4

    def turn_right():
        nonlocal direction_index
        direction_index = (direction_index + 1) % 4

    def repeat(n, command):
        for _ in range(n):
            command()

    tokens = program.split()
    i = 0
    while i < len(tokens):
        token = tokens[i]
        if token == "PENDOWN":
            pen_down = True
        elif token == "PENUP":
            pen_down = False
        elif token == "MOVE":
            move(int(tokens[i + 1]))
            i += 1
        elif token == "TURN":
            if tokens[i + 1] == "L":
                turn_left()
            else:
                turn_right()
            i += 1
        elif token == "REPEAT":
            n = int(tokens[i + 1])
            command = lambda: run_turtle(tokens[i + 2:i + 2 + n])
            repeat(n, command)
            i += 2 + n
        i += 1

    return (x, y, sorted(marks))

