class Matrix:
    def __init__(self, rows):
        self.rows = rows

    def __add__(self, other):
        if len(self.rows) != len(other.rows) or len(self.rows[0]) != len(other.rows[0]):
            raise ValueError("Matrices must have the same shape for addition")
        return Matrix([[self.rows[i][j] + other.rows[i][j] for j in range(len(self.rows[0]))] for i in range(len(self.rows))])

    def __mul__(self, other):
        if len(self.rows[0]) != len(other.rows):
            raise ValueError("Number of columns in self must match number of rows in other for multiplication")
        return Matrix([[sum(self.rows[i][k] * other.rows[k][j] for k in range(len(self.rows[0]))) for j in range(len(other.rows[0]))] for i in range(len(self.rows))])

    def transpose(self):
        return Matrix([[self.rows[j][i] for j in range(len(self.rows))] for i in range(len(self.rows[0]))])

    def det(self):
        if len(self.rows) != len(self.rows[0]):
            raise ValueError("Matrix must be square to compute determinant")
        if len(self.rows) == 1:
            return self.rows[0][0]
        det = 0
        for i in range(len(self.rows)):
            sign = (-1) ** i
            sub_matrix = [row[:i] + row[i+1:] for row in self.rows[1:]]
            det += sign * self.rows[0][i] * sub_matrix.det()
        return det

    def __eq__(self, other):
        if len(self.rows) != len(other.rows) or len(self.rows[0]) != len(other.rows[0]):
            return False
        return all(self.rows[i] == other.rows[i] for i in range(len(self.rows)))

