class Polynomial:
    def __init__(self, coeffs):
        self.coeffs = coeffs
        self.normalize()

    def normalize(self):
        while len(self.coeffs) > 1 and self.coeffs[-1] == 0:
            self.coeffs.pop()

    def __add__(self, other):
        if not isinstance(other, Polynomial):
            raise TypeError("Operand must be a Polynomial")
        max_len = max(len(self.coeffs), len(other.coeffs))
        coeffs = [0] * max_len
        for i in range(max_len):
            coeffs[i] = self.coeffs[i] if i < len(self.coeffs) else 0
            coeffs[i] += other.coeffs[i] if i < len(other.coeffs) else 0
        return Polynomial(coeffs)

    def __mul__(self, other):
        if not isinstance(other, Polynomial):
            raise TypeError("Operand must be a Polynomial")
        coeffs = [0] * (len(self.coeffs) + len(other.coeffs) - 1)
        for i in range(len(self.coeffs)):
            for j in range(len(other.coeffs)):
                coeffs[i + j] += self.coeffs[i] * other.coeffs[j]
        return Polynomial(coeffs)

    def evaluate(self, x):
        return sum(c * x**i for i, c in enumerate(self.coeffs))

    def derivative(self):
        return Polynomial([i * c for i, c in enumerate(self.coeffs)][1:])

    def __eq__(self, other):
        if not isinstance(other, Polynomial):
            return False
        return self.coeffs == other.coeffs

    def __str__(self):
        if not self.coeffs:
            return "0"
        terms = []
        for i, c in enumerate(self.coeffs):
            if c == 0:
                continue
            term = str(abs(c))
            if i > 0:
                term += "x"
            if i > 1:
                term += "^" + str(i)
            if c < 0:
                terms.append("-" + term)
            else:
                terms.append(term)
        return " + ".join(terms)
